  `title` VARCHAR(255) NOT NULL,
  `description` TEXT NULL DEFAULT NULL,
  `assigned_by` BIGINT UNSIGNED NOT NULL,
  `assigned_to` BIGINT UNSIGNED NOT NULL,
  `parent_id` BIGINT UNSIGNED NULL DEFAULT NULL,
  `start_date` DATE NULL DEFAULT NULL,
  `due_date` DATE NULL DEFAULT NULL,
  `status` ENUM('assigned', 'in_progress', 'completed', 'delegated', 'cancelled') NOT NULL,
  `priority` ENUM('low', 'medium', 'high') NOT NULL,
  `assigned_by_id` BIGINT UNSIGNED NOT NULL,
  `assigned_to_id` BIGINT UNSIGNED NOT NULL,
  `parent_id_id` BIGINT UNSIGNED NOT NULL,
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  INDEX `assignments_assigned_by_foreign` (`assigned_by` ASC) VISIBLE,
  INDEX `assignments_assigned_to_foreign` (`assigned_to` ASC) VISIBLE,
  INDEX `assignments_parent_id_foreign` (`parent_id` ASC) VISIBLE,
  CONSTRAINT `assignments_assigned_by_foreign`
    FOREIGN KEY (`assigned_by`)
    REFERENCES `facultyware`.`employees` (`id`),
  CONSTRAINT `assignments_assigned_to_foreign`
    FOREIGN KEY (`assigned_to`)
    REFERENCES `facultyware`.`employees` (`id`),
  CONSTRAINT `assignments_parent_id_foreign`
    FOREIGN KEY (`parent_id`)
    REFERENCES `facultyware`.`assignments` (`id`))
ENGINE = InnoDB
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


